3	struct ContentView: View {
4	    @Bindable var store: DemoVehicleStateStore
5	    let traceLogger: InMemoryTraceLogger
6	    let speech: any SpeechSynthesisEngine
7	
8	    @State private var commandText = "打开空调"
9	    @State private var lastReadback = "等待指令"
10	    @State private var errorText: String?
11	
12	    var body: some View {
13	        NavigationStack {
14	            VStack(alignment: .leading, spacing: 20) {
15	                commandBar
16	                vehicleCards
17	                tracePanel
18	            }
19	            .padding(24)
20	            .navigationTitle("MAformac")
21	        }
22	    }
23	
24	    private var commandBar: some View {
25	        HStack(spacing: 12) {
26	            TextField("输入车控指令", text: $commandText)
27	                .textFieldStyle(.roundedBorder)
28	
29	            Button {
30	                Task { await runCommand() }
31	            } label: {
32	                Label("执行", systemImage: "play.fill")
33	            }
34	            .buttonStyle(.borderedProminent)
35	        }
36	        .accessibilityIdentifier("command-bar")
37	    }
38	
39	    private var vehicleCards: some View {
40	        LazyVGrid(columns: [GridItem(.adaptive(minimum: 160), spacing: 12)], spacing: 12) {
41	            ForEach(store.cells) { cell in
42	                VehicleStateCard(cell: cell)
43	            }
44	        }
45	    }
46	
47	    private var tracePanel: some View {
48	        VStack(alignment: .leading, spacing: 8) {
49	            Text(lastReadback)
50	                .font(.headline)
51	            if let errorText {
52	                Text(errorText)
53	                    .foregroundStyle(.red)
54	            }
55	            ForEach(Array(traceLogger.entries.enumerated()), id: \.offset) { _, entry in
56	                Text("\(entry.stage.rawValue): \(entry.message)")
57	                    .font(.caption.monospaced())
58	                    .foregroundStyle(.secondary)
59	            }
60	        }
61	        .accessibilityIdentifier("trace-panel")
62	    }
63	
64	    @MainActor
65	    private func runCommand() async {
66	        errorText = nil
67	        let skeleton = DemoWalkingSkeleton(
68	            store: store,
69	            guardrail: DemoFastPathGuard(),
70	            traceLogger: traceLogger,
71	            speech: speech
72	        )
73	
74	        do {
75	            let readback = try await skeleton.handle(text: commandText)
76	            lastReadback = "\(readback.key): \(readback.actualValue)"
77	        } catch {
78	            errorText = "\(error)"
79	        }
80	    }
81	}
